const body = $json.body ?? $json;
const items = body.items ?? body.envelopeItems ?? body.envelope_items ?? [];
if (!Array.isArray(items) || items.length === 0) {
  throw new Error('No envelope items found in Documenso envelope response: ' + JSON.stringify(body).slice(0,2000));
}
const item = items.find(i => String(i.fileType || i.mimetype || '').includes('pdf')) || items[0];
const envelopeItemId = item.id || item.envelopeItemId || item.envelope_item_id;
if (!envelopeItemId) throw new Error('Missing envelope item id. Item: ' + JSON.stringify(item));
return [{ json: { envelopeItemId } }];

const r = $json.body ?? $json;
let files = r;
if (r && typeof r === 'object' && Array.isArray(r.files)) files = r.files;
if (!Array.isArray(files)) files = [files];
return [{ json: { new_attachments_json: JSON.stringify(files) } }];

